using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;

namespace YourNamespace.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly IWebHostEnvironment _hostingEnvironment;

        public FilesController(IWebHostEnvironment hostingEnvironment)
        {
            _hostingEnvironment = hostingEnvironment;
        }

        [HttpGet("uploads/{filename}")]
        public IActionResult GetUploadFile(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename cannot be empty.");
            }

            // Combine the web root path with the "uploads" subfolder
            var filePath = Path.Combine(_hostingEnvironment.WebRootPath, "uploads", filename);

            if (!System.IO.File.Exists(filePath))
            {
                // You might want to log this missing file
                return NotFound($"File '{filename}' not found.");
            }

            // Determine the content type
            var provider = new FileExtensionContentTypeProvider();
            if (!provider.TryGetContentType(filename, out string contentType))
            {
                contentType = "application/octet-stream"; // Default content type if unknown
            }

            // Return the file content
            return PhysicalFile(filePath, contentType);
        }
    }
